7	      expect(calculateBasePremium([{ type: "sword" }])).toBe(100);
8	    });
9	    it("should return 60 G base premium for a single amulet", () => {
10	      expect(calculateBasePremium([{ type: "amulet" }])).toBe(60);
11	    });
12	    it("should return 80 G base premium for a single staff", () => {
13	      expect(calculateBasePremium([{ type: "staff" }])).toBe(80);
14	    });
15	    it.todo("should return 40 G base premium for a single potion");
16	    it.todo("should return 25 G base premium for a single rune component");
17	  });
18	
19	  describe("Component block discount", () => {
20	    it.todo("should return 50 G base premium for 2 runes (no block)");
21	    it.todo("should return 60 G base premium for 3 runes (block discount applies)");
22	    it.todo("should return 100 G base premium for 4 runes (no block -- block requires exactly 3)");
23	    it.todo("should return 175 G base premium for 7 runes (no blocks possible)");
24	    it.todo("should return 75 G base premium for 2 runes + 1 moonstone (no block -- different types)");
25	    it.todo("should return 120 G base premium for 3 runes + 3 moonstones (two separate blocks)");
26	  });
27	
28	  describe("Item-specific premium modifiers", () => {
29	    it.todo("should add 50% cursed surcharge to the cursed item base premium only -- cursed sword (100) + plain amulet (60) = 210 G before policy modifiers and fee");
