33	  });
34	
35	  describe("Policy-wide premium modifiers", () => {
36	    it.todo("should apply 20% loyalty discount for customer with yearsWithMHPCO >= 2");
37	    it.todo("should apply loyalty discount for customer with exactly 2 years");
38	    it.todo("should not apply loyalty discount for customer with 1 year");
39	    it.todo("should add 10% first insurance surcharge on policy base premium (always applies per item in quote)");
40	    it.todo("should apply 15% follow-up discount on second and subsequent quotes in a scenario");
41	    it.todo("should add 5 G processing fee at the very end of premium calculation");
42	  });
43	
44	  describe("Empty and edge-case quotes", () => {
45	    it.todo("should return 5 G premium for empty item list (processing fee only)");
46	  });
47	
48	  describe("Modifier application order", () => {
49	    it.todo("should apply item-specific modifiers to item base premium, then policy-wide modifiers to sum, then fee last");
50	  });
51	
52	  describe("Rounding in MHPCO favor", () => {
53	    it.todo("should round premium UP (ceil) -- a calculation yielding 197.5 G becomes 198 G");
54	    it.todo("should round payout DOWN (floor) -- a calculation yielding 350.5 G becomes 350 G");
55	    it.todo("should keep intermediates as fractions and round only the final result");
56	  });
57	
58	  describe("Integration: newcomer with cursed sword", () => {
59	    it.todo("should compute 165 G premium for newcomer (0 years, first contract) with cursed sword (steel, enchantment 3) -- 100 base + 50 curse + 10 first insurance + 5 fee");
60	  });
61	
62	  describe("Integration: long-standing customer second contract", () => {
63	    it.todo("should compute 160 G premium for 3-year customer on second quote with cursed sword (steel, enchantment 7) -- 100 + 50 + 30 - 20 + 10 - 15 + 5 = 160 G");
64	  });
65	
66	  describe("Claim: deductible", () => {
67	    it.todo("should apply 100 G deductible per damaged item -- sword 500 G + amulet 300 G = 600 G payout");
68	  });
69	
70	  describe("Claim: standard reimbursement (no special clauses)", () => {
71	    it.todo("should return 400 G payout for regular sword (steel, enchantment 3) with 500 G damage -- full reimbursement minus 100 G deductible");
72	    it.todo("should return 100 G payout for rune with 200 G damage -- full reimbursement minus 100 G deductible, no special clauses for components");
73	  });
74	
75	  describe("Claim: high-enchantment reimbursement", () => {
76	    it.todo("should reimburse at 50% for item with enchantment >= 8 then apply deductible -- steel sword enchantment 9, 1000 G damage = 400 G payout");
77	  });
78	
79	  describe("Claim: dragon material reimbursement", () => {
80	    it.todo("should fully reimburse dragon-material item then apply deductible -- dragon sword enchantment 5, 800 G damage = 700 G payout");
81	  });
82	
83	  describe("Claim: enchantment >= 8 AND dragon material", () => {
84	    it.todo("should apply 50% rule when both dragon material and enchantment >= 8 -- dragon sword enchantment 9, 1000 G damage = 400 G payout");
