95	
96	  describe("Claim: multiple items of the same type", () => {
97	    it.todo("should compute insurance sum 2000 G and cap 4000 G for two swords");
98	    it.todo("should treat each damage entry for same-type items separately with its own deductible");
99	    it.todo("should reject claim when damages array has more entries of a type than policy covers -- CLI exits non-zero");
100	  });
101	
102	  describe("Error handling", () => {
103	    it.todo("should exit non-zero and write to stderr for unknown item type in quote (e.g. broomstick)");
104	    it.todo("should exit non-zero and write to stderr for claim referencing item not in policy");
105	    it.todo("should exit non-zero and write to stderr for negative damage amount");
106	    it.todo("should not write results to stdout on error");
107	  });
108	
109	  describe("CLI input/output format", () => {
110	    it.todo("should read JSON scenario from stdin and write JSON results to stdout");
111	    it.todo("should output quote result with premium field as integer");
112	    it.todo("should output claim result with payout and remainingCap fields as integers");
